#include<bits/stdc++.h>
using namespace std;
void f(string a1, string a2) {
		if (a1 == "\0" || a2 == "\0" || a1.size()==1 || a1.size()==0) {
			if(!(a1 == "\0" || a2 == "\0")){
				cout<<a1[0];
			}
			
			return;
		}
		char b = a2[a1.size() - 1];
		int pos = a1.find(b);
		cout << b;
		f(a1.substr(0, pos), a2.substr(0, pos));
		f(a1.substr(pos + 1), a2.substr(pos, a1.size() - pos - 1));

	}
	int main() {
		string a1, a2;
		cin >> a1 >> a2;
		f(a1, a2);
		return 0;
	}
